// Split audio into <25MB chunks for OpenAI Whisper API limit
const items = $input.all();
const MAX_CHUNK = 24 * 1024 * 1024; // 24MB safe limit
const results = [];

for (let i = 0; i < items.length; i++) {
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

  if (buffer.length <= MAX_CHUNK) {
    // Small enough — pass through as single chunk
    results.push({
      json: { chunkIndex: 0, totalChunks: 1 },
      binary: items[i].binary
    });
    continue;
  }

  // Split into multiple chunks
  const totalChunks = Math.ceil(buffer.length / MAX_CHUNK);
  for (let c = 0; c < totalChunks; c++) {
    const start = c * MAX_CHUNK;
    const end = Math.min(start + MAX_CHUNK, buffer.length);
    const chunk = Buffer.from(buffer.subarray(start, end));
    results.push({
      json: { chunkIndex: c, totalChunks },
      binary: {
        data: await this.helpers.prepareBinaryData(
          chunk, 'chunk_' + c + '.mp3', 'audio/mpeg'
        )
      }
    });
  }
}

return results;

// Merge transcript chunks and attach episode metadata
const items = $input.all();
const rssData = $('RSS Feed Trigger').first().json;

// Chunks arrive in order — join them
const transcript = items
  .map(item => item.json.text || '')
  .join('\n\n')
  .trim();

return [{
  json: {
    title: rssData.title || 'Untitled Episode',
    date: rssData.isoDate || rssData.pubDate || new Date().toISOString(),
    link: rssData.link || '',
    transcript: transcript,
    wordCount: transcript.split(/\s+/).filter(w => w.length > 0).length,
    transcribedAt: new Date().toISOString()
  }
}];
